import{_ as a,o as e,c as d,a2 as l}from"./chunks/framework.BZO4qERu.js";const p=JSON.parse('{"title":"騎砍2 | 戰鬥技巧完全指南：從被砍到砍人","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/combat-tactics.md","filePath":"bannerlord/combat-tactics.md"}'),r={name:"bannerlord/combat-tactics.md"};function i(h,t,n,s,o,c){return e(),d("div",null,[...t[0]||(t[0]=[l(`<h1 id="騎砍2-戰鬥技巧完全指南-從被砍到砍人" tabindex="-1">騎砍2 | 戰鬥技巧完全指南：從被砍到砍人 <a class="header-anchor" href="#騎砍2-戰鬥技巧完全指南-從被砍到砍人" aria-label="Permalink to &quot;騎砍2 | 戰鬥技巧完全指南：從被砍到砍人&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>騎砍不是無雙割草，戰鬥系統有四向攻擊、格擋、踢擊、騎乘加成……搞懂這些，你就不再是那個被山賊追著跑的路人甲。</p><hr><h2 id="一、基礎操作-四向攻擊與格擋" tabindex="-1">一、基礎操作：四向攻擊與格擋 <a class="header-anchor" href="#一、基礎操作-四向攻擊與格擋" aria-label="Permalink to &quot;一、基礎操作：四向攻擊與格擋&quot;">​</a></h2><h3 id="_1-1-攻擊方向" tabindex="-1">1.1 攻擊方向 <a class="header-anchor" href="#_1-1-攻擊方向" aria-label="Permalink to &quot;1.1 攻擊方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>操作</th><th>效果</th><th>使用場景</th></tr></thead><tbody><tr><td>滑鼠向上 + 左鍵</td><td>上劈</td><td>傷害最高，對付無盾敵人</td></tr><tr><td>滑鼠向下 + 左鍵</td><td>下砍</td><td>打腳、破盾後補刀</td></tr><tr><td>滑鼠向左/右 + 左鍵</td><td>橫砍</td><td>範圍最大，騎馬首選</td></tr><tr><td>滑鼠移動 + X 鍵</td><td>刺擊</td><td>長矛/長桿用，騎馬傷害×3</td></tr></tbody></table><h3 id="_1-2-格擋" tabindex="-1">1.2 格擋 <a class="header-anchor" href="#_1-2-格擋" aria-label="Permalink to &quot;1.2 格擋&quot;">​</a></h3><ul><li><strong>有盾牌</strong>：舉右鍵自動格擋（但會消耗盾牌耐久）</li><li><strong>無盾牌</strong>：右鍵 + 滑鼠方向手動格擋（高手向）</li><li><strong>踢擊（E鍵）</strong>：破防神技！對面舉盾 → 踢開 → 立刻補一刀</li></ul><h3 id="_1-3-騎乘戰鬥" tabindex="-1">1.3 騎乘戰鬥 <a class="header-anchor" href="#_1-3-騎乘戰鬥" aria-label="Permalink to &quot;1.3 騎乘戰鬥&quot;">​</a></h3><ul><li>騎馬時武器傷害 = 基礎傷害 × 速度倍率</li><li>高速衝鋒一刀可打出 2-3 倍傷害</li><li>長桿武器騎乘時會自動架矛</li></ul><hr><h2 id="二、單挑三招" tabindex="-1">二、單挑三招 <a class="header-anchor" href="#二、單挑三招" aria-label="Permalink to &quot;二、單挑三招&quot;">​</a></h2><h3 id="_2-1-繞圈破盾流-新手最強" tabindex="-1">2.1 繞圈破盾流（新手最強） <a class="header-anchor" href="#_2-1-繞圈破盾流-新手最強" aria-label="Permalink to &quot;2.1 繞圈破盾流（新手最強）&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>全程舉盾 → 繞對手逆時針轉圈 → 等對手砍空 →</span></span>
<span class="line"><span>立刻回一刀橫砍 → 後退 → 重複</span></span></code></pre></div><h3 id="_2-2-踢擊破防流" tabindex="-1">2.2 踢擊破防流 <a class="header-anchor" href="#_2-2-踢擊破防流" aria-label="Permalink to &quot;2.2 踢擊破防流&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>對手舉盾 → E鍵踢開 → 補上劈或刺擊 → 後退 → 重複</span></span></code></pre></div><h3 id="_2-3-騎馬單挑" tabindex="-1">2.3 騎馬單挑 <a class="header-anchor" href="#_2-3-騎馬單挑" aria-label="Permalink to &quot;2.3 騎馬單挑&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>繞對方騎兵逆時針 → 從左側超車 → 一刀砍馬 →</span></span>
<span class="line"><span>馬倒下人摔落 → 補刀收割</span></span></code></pre></div><hr><h2 id="三、野戰指揮" tabindex="-1">三、野戰指揮 <a class="header-anchor" href="#三、野戰指揮" aria-label="Permalink to &quot;三、野戰指揮&quot;">​</a></h2><h3 id="_3-1-快捷鍵" tabindex="-1">3.1 快捷鍵 <a class="header-anchor" href="#_3-1-快捷鍵" aria-label="Permalink to &quot;3.1 快捷鍵&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">鍵</th><th>功能</th></tr></thead><tbody><tr><td style="text-align:center;">F1</td><td>移動/位置指令</td></tr><tr><td style="text-align:center;">F2</td><td>朝向</td></tr><tr><td style="text-align:center;">F3</td><td>陣型</td></tr><tr><td style="text-align:center;">F4</td><td>開火/停火</td></tr><tr><td style="text-align:center;">F6</td><td>交給你指揮（AI 自動）</td></tr></tbody></table><h3 id="_3-2-錘砧戰術" tabindex="-1">3.2 錘砧戰術 <a class="header-anchor" href="#_3-2-錘砧戰術" aria-label="Permalink to &quot;3.2 錘砧戰術&quot;">​</a></h3><p>最經典的戰術：步兵扛線（砧）+ 騎兵兩面包抄（錘）。</p><ol><li>步兵 F3+F2 開盾牆面向敵方</li><li>弓手放在步兵後方高處</li><li>騎兵分兩隊放側翼</li><li>敵方接觸步兵 → 騎兵 F1+F3 繞背衝鋒</li></ol><h3 id="_3-3-弓騎風箏流" tabindex="-1">3.3 弓騎風箏流 <a class="header-anchor" href="#_3-3-弓騎風箏流" aria-label="Permalink to &quot;3.3 弓騎風箏流&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>弓騎 F1+F4 散開 → F4 自由射擊 →</span></span>
<span class="line"><span>敵方追弓騎（陣型拉散）→ 你帶重騎兵衝鋒敵方後排 →</span></span>
<span class="line"><span>步兵推進收尾</span></span></code></pre></div><h3 id="_3-4-地形利用" tabindex="-1">3.4 地形利用 <a class="header-anchor" href="#_3-4-地形利用" aria-label="Permalink to &quot;3.4 地形利用&quot;">​</a></h3><table tabindex="0"><thead><tr><th>地形</th><th>效果</th></tr></thead><tbody><tr><td>高地</td><td>弓兵射程+傷害 +20%</td></tr><tr><td>河流/橋</td><td>窄口堵路，10 個步兵扛 50 人</td></tr><tr><td>森林</td><td>騎兵衝鋒速度 -50%，步兵主場</td></tr></tbody></table><hr><h2 id="四、攻城戰" tabindex="-1">四、攻城戰 <a class="header-anchor" href="#四、攻城戰" aria-label="Permalink to &quot;四、攻城戰&quot;">​</a></h2><h3 id="_4-1-進攻" tabindex="-1">4.1 進攻 <a class="header-anchor" href="#_4-1-進攻" aria-label="Permalink to &quot;4.1 進攻&quot;">​</a></h3><ol><li>造投石機 → 優先打城牆和敵方投石車</li><li>步兵推攻城塔 + 破門錘</li><li>弓兵在城下壓制城牆守軍</li><li>塔靠牆 → <strong>不要第一個上！</strong></li><li>城牆戰舉盾推進，先清弓兵再打步兵</li></ol><h3 id="_4-2-防守" tabindex="-1">4.2 防守 <a class="header-anchor" href="#_4-2-防守" aria-label="Permalink to &quot;4.2 防守&quot;">​</a></h3><ul><li>投石車優先打攻城塔和破門錘</li><li>弓兵放城牆射推塔的敵兵</li><li>最強步兵放城門後準備巷戰</li></ul><hr><h2 id="五、武器組合推薦" tabindex="-1">五、武器組合推薦 <a class="header-anchor" href="#五、武器組合推薦" aria-label="Permalink to &quot;五、武器組合推薦&quot;">​</a></h2><table tabindex="0"><thead><tr><th>組合</th><th>武器 1</th><th>武器 2</th><th>武器 3</th><th>武器 4</th><th>適合</th></tr></thead><tbody><tr><td>均衡流</td><td>單手劍+盾</td><td>長桿</td><td>弓</td><td>箭矢</td><td>新手</td></tr><tr><td>騎兵流</td><td>長槍</td><td>單手劍+盾</td><td>—</td><td>—</td><td>騎兵專精</td></tr><tr><td>弓騎流</td><td>弓</td><td>箭矢×2</td><td>單手劍</td><td>盾</td><td>庫塞特</td></tr><tr><td>步兵流</td><td>雙手武器</td><td>單手+盾</td><td>投擲</td><td>—</td><td>攻城向</td></tr></tbody></table><hr><h2 id="結語" tabindex="-1">結語 <a class="header-anchor" href="#結語" aria-label="Permalink to &quot;結語&quot;">​</a></h2><p>競技場練單挑 → 劫匪練騎砍 → 當傭兵練指揮 → 攻城練戰術。一步一步來，卡拉迪亞沒有你打不贏的仗。</p><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li><li><a href="./kingdom-building.html">騎砍2 | 自立為王</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>`,51)])])}const u=a(r,[["render",i]]);export{p as __pageData,u as default};
